                                                        <>
                                                            <span className="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true"></span>
                                                            Exporting...
                                                        </>
                                                    ) : (
                                                        <>
                                                            <i className="bi bi-file-earmark-excel me-2"></i>
                                                            Export to Excel
                                                        </>
                                                    )}
                                                </button>

                                                {/* Save Button - Task: T055 [US3-Impl] */}
                                                <button
                                                    className="btn btn-primary"
                                                    onClick={handleSave}
                                                    disabled={saving}
                                                >
                                                    {saving ? (
                                                        <>
                                                            <span className="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true"></span>
                                                            Saving...
                                                        </>
                                                    ) : (
                                                        <>
                                                            <i className="bi bi-database-add me-2"></i>
                                                            Save to Database
                                                        </>
                                                    )}
                                                </button>
                                            </div>
                                        )}
                                    </div>

                                    {sortedVulnerabilities.length === 0 ? (
                                        <p className="text-muted">
                                            {(queryResponse.vulnerabilities?.length ?? 0) === 0
                                                ? 'No vulnerabilities found for this system.'
                                                : 'No vulnerabilities match the current filters.'}
                                        </p>
                                    ) : (
                                        <>
                                        <div className="table-responsive">
                                            <table className="table table-striped table-hover">
                                                <thead>
                                                    <tr>
                                                        <th
                                                            onClick={() => handleSort('cveId')}
                                                            style={{ cursor: 'pointer' }}
                                                        >
                                                            CVE
                                                            <SortIcon field="cveId" />
                                                        </th>
                                                        <th
                                                            onClick={() => handleSort('severity')}
                                                            style={{ cursor: 'pointer' }}
                                                        >
                                                            Severity
                                                            <SortIcon field="severity" />
                                                        </th>
                                                        <th
                                                            onClick={() => handleSort('affectedProduct')}
                                                            style={{ cursor: 'pointer' }}
                                                        >
                                                            Product
                                                            <SortIcon field="affectedProduct" />
                                                        </th>
                                                        <th
                                                            onClick={() => handleSort('daysOpen')}
                                                            style={{ cursor: 'pointer' }}
                                                        >
                                                            Days Open
                                                            <SortIcon field="daysOpen" />
                                                        </th>
                                                        <th
                                                            onClick={() => handleSort('hasException')}
                                                            style={{ cursor: 'pointer' }}
                                                        >
                                                            Exception
                                                            <SortIcon field="hasException" />
                                                        </th>
                                                        <th>AWS Account</th>
                                                    </tr>
                                                </thead>
                                                <tbody>
                                                    {sortedVulnerabilities.map((vuln) => (
                                                        <tr key={vuln.id}>
                                                            <td>
                                                                <CveLink cveId={vuln.cveId} />
                                                            </td>
                                                            <td>
                                                                <span className={`badge ${getSeverityBadgeClass(vuln.severity)}`}>
                                                                    {vuln.severity}
                                                                </span>
                                                            </td>
                                                            <td style={{ maxWidth: '200px', overflow: 'hidden', textOverflow: 'ellipsis' }}>
                                                                {vuln.affectedProduct || '-'}
                                                            </td>
                                                            <td>{vuln.daysOpen || '-'}</td>
                                                            <td>
                                                                {getExceptionBadge(vuln.hasException, vuln.exceptionReason, vuln.daysOpen)}
                                                            </td>
                                                            <td>{queryResponse?.cloudAccountId || '-'}</td>
                                                        </tr>
                                                    ))}
                                                </tbody>
                                            </table>
                                        </div>

                                        {/* Pagination Controls */}
                                        {totalPages > 1 && (
                                            <nav aria-label="Vulnerability pagination" className="mt-3">
                                                <div className="d-flex justify-content-between align-items-center">
                                                    <small className="text-muted">
                                                        Page {currentPage + 1} of {totalPages.toLocaleString()}
                                                    </small>
                                                    <ul className="pagination mb-0">
                                                        <li className={`page-item ${currentPage === 0 ? 'disabled' : ''}`}>
                                                            <button
                                                                className="page-link"
                                                                onClick={() => handlePageChange(0)}
                                                                disabled={currentPage === 0 || loading}
                                                            >
                                                                First
                                                            </button>
                                                        </li>
                                                        <li className={`page-item ${currentPage === 0 ? 'disabled' : ''}`}>
                                                            <button
                                                                className="page-link"
                                                                onClick={() => handlePageChange(currentPage - 1)}
                                                                disabled={currentPage === 0 || loading}
                                                            >
                                                                Previous
                                                            </button>
                                                        </li>
                                                        <li className={`page-item ${currentPage >= totalPages - 1 ? 'disabled' : ''}`}>
                                                            <button
                                                                className="page-link"
                                                                onClick={() => handlePageChange(currentPage + 1)}
                                                                disabled={currentPage >= totalPages - 1 || loading}
                                                            >
                                                                Next
                                                            </button>
                                                        </li>
                                                        <li className={`page-item ${currentPage >= totalPages - 1 ? 'disabled' : ''}`}>
                                                            <button
                                                                className="page-link"
                                                                onClick={() => handlePageChange(totalPages - 1)}
                                                                disabled={currentPage >= totalPages - 1 || loading}
                                                            >
                                                                Last
                                                            </button>
                                                        </li>
                                                    </ul>
                                                </div>
                                            </nav>
                                        )}
                                        </>
                                    )}
                                </div>
                            </div>
                        </div>
                    </div>
                </>
            )}

            {/* Back to Home button */}
            <div className="row mt-4">
                <div className="col-12">
                    <a href="/" className="btn btn-secondary">
                        <i className="bi bi-house me-2"></i>
                        Back to Home
                    </a>
                </div>
            </div>
        </div>
    );
};

